    public Object parseCurrency(Object currency)
    {
        Object id = this.safeValue(currency, "name");
        Object code = this.safeCurrencyCode(id);
        Object depositEnabled = this.safeValue(currency, "deposit-enabled");
        Object withdrawEnabled = this.safeValue(currency, "withdraw-enabled");
        Object countryDisabled = this.safeValue(currency, "country-disabled");
        Object visible = this.safeBool(currency, "visible", false);
        Object state = this.safeString(currency, "state");
        Object active = Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(visible) && Helpers.isTrue(depositEnabled)) && Helpers.isTrue(withdrawEnabled)) && Helpers.isTrue((Helpers.isEqual(state, "online")))) && !Helpers.isTrue(countryDisabled);
        Object name = this.safeString(currency, "display-name");
        Object precision = this.parseNumber(this.parsePrecision(this.safeString(currency, "withdraw-precision")));
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "code", code );
            put( "type", "crypto" );
            put( "name", name );
            put( "active", active );
            put( "deposit", depositEnabled );
            put( "withdraw", withdrawEnabled );
            put( "fee", null );
            put( "precision", precision );
            put( "networks", null );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", precision );
                    put( "max", null );
                }} );
                put( "deposit", new java.util.HashMap<String, Object>() {{
                    put( "min", BittradeCore.this.safeNumber(currency, "deposit-min-amount") );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", BittradeCore.this.safeNumber(currency, "withdraw-min-amount") );
                    put( "max", null );
                }} );
            }} );
            put( "info", currency );
        }});
    }

    public Object parseBalance(Object response)
    {
        Object balances = this.safeValue(Helpers.GetValue(response, "data"), "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balance = Helpers.GetValue(balances, i);
            Object currencyId = this.safeString(balance, "currency");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = null;
            if (Helpers.isTrue(Helpers.inOp(result, code)))
            {
                account = Helpers.GetValue(result, code);
            } else
            {
                account = this.account();
            }
            if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(balance, "type"), "trade")))
            {
                Helpers.addElementToObject(account, "free", this.safeString(balance, "balance"));
            }
            if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(balance, "type"), "frozen")))
            {
                Helpers.addElementToObject(account, "used", this.safeString(balance, "balance"));
            }
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

