    public java.util.concurrent.CompletableFuture<Object> fetchOpenOrdersV2(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
            }
            Object accountId = this.safeString(parameters, "account-id");
            if (Helpers.isTrue(Helpers.isEqual(accountId, null)))
            {
                // pick the first account
                (this.loadAccounts()).join();
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(this.accounts)); i++)
                {
                    Object account = Helpers.GetValue(this.accounts, i);
                    if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(account, "type"), "spot")))
                    {
                        accountId = this.safeString(account, "id");
                        if (Helpers.isTrue(!Helpers.isEqual(accountId, null)))
                        {
                            break;
                        }
                    }
                }
            }
            Helpers.addElementToObject(request, "account-id", accountId);
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "size", limit);
            }
            Object omitted = this.omit(parameters, "account-id");
            Object response = (this.privateGetOrderOpenOrders(this.extend(request, omitted))).join();
            //
            //     {
            //         "status":"ok",
            //         "data":[
            //             {
            //                 "symbol":"ethusdt",
            //                 "source":"api",
            //                 "amount":"0.010000000000000000",
            //                 "account-id":1528640,
            //                 "created-at":1561597491963,
            //                 "price":"400.000000000000000000",
            //                 "filled-amount":"0.0",
            //                 "filled-cash-amount":"0.0",
            //                 "filled-fees":"0.0",
            //                 "id":38477101630,
            //                 "state":"submitted",
            //                 "type":"sell-limit"
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOrders(data, market, since, limit);
        });

    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "partial-filled", "open" );
            put( "partial-canceled", "canceled" );
            put( "filled", "closed" );
            put( "canceled", "canceled" );
            put( "submitted", "open" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //     {                  id:  13997833014,
        //                    "symbol": "ethbtc",
        //              "account-id":  3398321,
        //                    "amount": "0.045000000000000000",
        //                     "price": "0.034014000000000000",
        //              "created-at":  1545836976871,
        //                      "type": "sell-limit",
        //            "field-amount": "0.045000000000000000", // they have fixed it for filled-amount
        //       "field-cash-amount": "0.001530630000000000", // they have fixed it for filled-cash-amount
        //              "field-fees": "0.000003061260000000", // they have fixed it for filled-fees
        //             "finished-at":  1545837948214,
        //                    "source": "spot-api",
        //                     "state": "filled",
        //             "canceled-at":  0                      }
        //
        //     {                  id:  20395337822,
        //                    "symbol": "ethbtc",
        //              "account-id":  5685075,
        //                    "amount": "0.001000000000000000",
        //                     "price": "0.0",
        //              "created-at":  1545831584023,
        //                      "type": "buy-market",
        //            "field-amount": "0.029100000000000000", // they have fixed it for filled-amount
        //       "field-cash-amount": "0.000999788700000000", // they have fixed it for filled-cash-amount
        //              "field-fees": "0.000058200000000000", // they have fixed it for filled-fees
        //             "finished-at":  1545831584181,
        //                    "source": "spot-api",
        //                     "state": "filled",
        //             "canceled-at":  0                      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "id");
        Object side = null;
        Object type = null;
        Object status = null;
        if (Helpers.isTrue(Helpers.inOp(order, "type")))
        {
            Object orderType = Helpers.split(Helpers.GetValue(order, "type"), "-");
            side = Helpers.GetValue(orderType, 0);
            type = Helpers.GetValue(orderType, 1);
            status = this.parseOrderStatus(this.safeString(order, "state"));
        }
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeInteger(order, "created-at");
        Object clientOrderId = this.safeString(order, "client-order-id");
        Object amount = this.safeString(order, "amount");
        Object filled = this.safeString2(order, "filled-amount", "field-amount"); // typo in their API, filled amount
        Object price = this.safeString(order, "price");
        Object cost = this.safeString2(order, "filled-cash-amount", "field-cash-amount"); // same typo
        Object feeCost = this.safeString2(order, "filled-fees", "field-fees"); // typo in their API, filled fees
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            Object feeCurrency = ((Helpers.isTrue((Helpers.isEqual(side, "sell"))))) ? Helpers.GetValue(market, "quote") : Helpers.GetValue(market, "base");
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", feeCurrency );
            }};
        }
        final Object finalMarket = market;
        final Object finalType = type;
        final Object finalSide = side;
        final Object finalStatus = status;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", BittradeCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", finalType );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", finalSide );
            put( "price", price );
            put( "triggerPrice", null );
            put( "average", null );
            put( "cost", cost );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", null );
            put( "status", finalStatus );
            put( "fee", finalFee );
            put( "trades", null );
        }}, market);
    }

    /**
     * @method
     * @name bittrade#createMarketBuyOrderWithCost
     * @description create a market buy order by providing the symbol and cost
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {float} cost how much you want to trade in units of the quote currency
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createMarketBuyOrderWithCost(Object symbol, Object cost, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " createMarketBuyOrderWithCost() supports spot orders only")) ;
            }
            Helpers.addElementToObject(parameters, "createMarketBuyOrderRequiresPrice", false);
            return (this.createOrder(symbol, "market", "buy", cost, null, parameters)).join();
        });

    }

    /**
     * @method
     * @name bittrade#createOrder
     * @description create a trade order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side2, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object side3 = side2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object side = side3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            (this.loadAccounts()).join();
            Object market = this.market(symbol);
            final Object finalSide = side;
            final Object finalType = type;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "account-id", Helpers.GetValue(Helpers.GetValue(BittradeCore.this.accounts, 0), "id") );
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "type", Helpers.add(Helpers.add(finalSide, "-"), finalType) );
            }};
            Object clientOrderId = this.safeString2(parameters, "clientOrderId", "client-order-id"); // must be 64 chars max and unique within 24 hours
            if (Helpers.isTrue(Helpers.isEqual(clientOrderId, null)))
            {
                Object broker = this.safeValue(this.options, "broker", new java.util.HashMap<String, Object>() {{}});
                Object brokerId = this.safeString(broker, "id");
                Helpers.addElementToObject(request, "client-order-id", Helpers.add(brokerId, this.uuid()));
            } else
            {
                Helpers.addElementToObject(request, "client-order-id", clientOrderId);
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId", "client-order-id")));
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(type, "market"))) && Helpers.isTrue((Helpers.isEqual(side, "buy")))))
            {
                Object quoteAmount = null;
                Object createMarketBuyOrderRequiresPrice = true;
                var createMarketBuyOrderRequiresPriceparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "createMarketBuyOrderRequiresPrice", true);
                createMarketBuyOrderRequiresPrice = ((java.util.List<Object>) createMarketBuyOrderRequiresPriceparametersVariable).get(0);
                parameters = ((java.util.List<Object>) createMarketBuyOrderRequiresPriceparametersVariable).get(1);
                Object cost = this.safeNumber(parameters, "cost");
                parameters = this.omit(parameters, "cost");
                if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
                {
                    quoteAmount = this.amountToPrecision(symbol, cost);
                } else if (Helpers.isTrue(createMarketBuyOrderRequiresPrice))
                {
                    if (Helpers.isTrue(Helpers.isEqual(price, null)))
                    {
                        throw new InvalidOrder((String)Helpers.add(this.id, " createOrder() requires the price argument for market buy orders to calculate the total cost to spend (amount * price), alternatively set the createMarketBuyOrderRequiresPrice option or param to false and pass the cost to spend in the amount argument")) ;
                    } else
                    {
                        // despite that cost = amount * price is in quote currency and should have quote precision
                        // the exchange API requires the cost supplied in 'amount' to be of base precision
                        // more about it here:
                        // https://github.com/ccxt/ccxt/pull/4395
                        // https://github.com/ccxt/ccxt/issues/7611
                        // we use amountToPrecision here because the exchange requires cost in base precision
                        Object amountString = this.numberToString(amount);
                        Object priceString = this.numberToString(price);
                        quoteAmount = this.amountToPrecision(symbol, Precise.stringMul(amountString, priceString));
                    }
                } else
                {
                    quoteAmount = this.amountToPrecision(symbol, amount);
                }
                Helpers.addElementToObject(request, "amount", quoteAmount);
            } else
            {
                Helpers.addElementToObject(request, "amount", this.amountToPrecision(symbol, amount));
            }
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(type, "limit")) || Helpers.isTrue(Helpers.isEqual(type, "ioc"))) || Helpers.isTrue(Helpers.isEqual(type, "limit-maker"))) || Helpers.isTrue(Helpers.isEqual(type, "stop-limit"))) || Helpers.isTrue(Helpers.isEqual(type, "stop-limit-fok"))))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
            Object method = Helpers.GetValue(this.options, "createOrderMethod");
            Object response = ((java.util.concurrent.CompletableFuture<Object>)Helpers.callDynamically(this, method, new Object[] { this.extend(request, parameters) })).join();
            Object id = this.safeString(response, "data");
            final Object finalPrice = price;
            return this.safeOrder(new java.util.HashMap<String, Object>() {{
                put( "info", response );
                put( "id", id );
                put( "timestamp", null );
                put( "datetime", null );
                put( "lastTradeTimestamp", null );
                put( "status", null );
                put( "symbol", symbol );
                put( "type", finalType );
                put( "side", finalSide );
                put( "price", finalPrice );
                put( "amount", amount );
                put( "filled", null );
                put( "remaining", null );
                put( "cost", null );
                put( "trades", null );
                put( "fee", null );
                put( "clientOrderId", null );
                put( "average", null );
            }}, market);
        });

    }

